SELECT s.survey_id as surveyId , s.title as title , DATE_FORMAT(s.created_at, '%Y-%m-%d') as createdAt , s.view_count as viewCount , s.use_yn as useYn , s.loginID as loginId , s.course_id as courseId , u.name as loginName , CASE WHEN sr.loginID IS NOT NULL THEN 'Y' ELSE 'N' END as responseYn FROM survey s LEFT JOIN tb_userinfo u ON s.loginID = u.loginID LEFT JOIN ( SELECT DISTINCT survey_id, loginID FROM survey_response
WHERE loginID = #{loginID}
) sr ON s.survey_id = sr.survey_id
and s.title Like CONCAT('%', #{title}, '%')
and DATE(s.created_at) >= #{from_date}
and DATE(s.created_at) <= #{to_date}
ORDER BY s.survey_id DESC LIMIT #{pageIndex}, #{pageSize}

SELECT COUNT(*)
FROM survey


